import random

class Grid:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[None for _ in range(width)] for _ in range(height)]

    def is_valid_move(self, shape, offset_x, offset_y):
        """Checks if the shape can be placed at the given offset without collisions or going out of bounds."""
        for x, y, color in shape.blocks:
            grid_x = x + offset_x
            grid_y = y + offset_y

            if grid_x < 0 or grid_x >= self.width or grid_y < 0 or grid_y >= self.height or self.grid[grid_y][grid_x] is not None:
                return False
        return True

    def place_shape(self, shape, offset_x, offset_y):
        """Places the shape's blocks (converted to gem colors) onto the grid."""
        for x, y, color in shape.blocks:
            grid_x = x + offset_x
            grid_y = y + offset_y
            self.grid[grid_y][grid_x] = color  # Store color as gem type

    def get_cell_color(self, x, y):
        """Returns the color of the gem at the given coordinates, or None if the cell is empty."""
        if 0 <= x < self.width and 0 <= y < self.height:
            return self.grid[y][x]
        else:
            return None  # Out of bounds

    def set_cell_color(self, x, y, color):
         """Sets the color of the gem at the given coordinates."""
         if 0 <= x < self.width and 0 <= y < self.height:
             self.grid[y][x] = color

    def clear_cell(self, x, y):
        """Clears the cell at the given coordinates by setting it to None."""
        if 0 <= x < self.width and 0 <= y < self.height:
            self.grid[y][x] = None

    def is_row_full(self, row_index):
        """Checks if a row is completely filled with gems (no None values)."""
        return all(self.grid[row_index])

    def clear_row(self, row_index):
        """Clears all cells in a given row."""
        for x in range(self.width):
            self.grid[row_index][x] = None

    def drop_row(self, row_index):
        """Moves all rows above the given row down by one."""
        for y in range(row_index, 0, -1):
            self.grid[y] = self.grid[y - 1][:]  # Copy the row above
        self.grid[0] = [None] * self.width  # Clear the top row

    def clear_matches(self):
        """Find and clear match-3 or more chains, return the cleared coordinates."""
        matches = self.find_matches()
        cleared_coordinates = set()
        for x, y in matches:
            self.clear_cell(x, y)
            cleared_coordinates.add((x, y))
        return cleared_coordinates

    def find_matches(self):
        """Finds all horizontal and vertical match-3 or more chains."""
        matches = set()

        # Horizontal matches
        for y in range(self.height):
            for x in range(self.width - 2):
                color = self.get_cell_color(x, y)
                if color is None:
                    continue
                if (self.get_cell_color(x + 1, y) == color and
                        self.get_cell_color(x + 2, y) == color):
                    match_length = 3
                    while (x + match_length < self.width and
                           self.get_cell_color(x + match_length, y) == color):
                        match_length += 1
                    for i in range(match_length):
                        matches.add((x + i, y))

        # Vertical matches
        for x in range(self.width):
            for y in range(self.height - 2):
                color = self.get_cell_color(x, y)
                if color is None:
                    continue
                if (self.get_cell_color(x, y + 1) == color and
                        self.get_cell_color(x, y + 2) == color):
                    match_length = 3
                    while (y + match_length < self.height and
                           self.get_cell_color(x, y + match_length) == color):
                        match_length += 1
                    for i in range(match_length):
                        matches.add((x, y + i))

        return list(matches)

    def apply_gravity(self):
        """Applies gravity to the grid, moving floating gems down."""
        for x in range(self.width):
            empty_space = -1
            for y in range(self.height):
                if self.grid[y][x] is None:
                    if empty_space == -1:
                        empty_space = y
                else:
                    if empty_space != -1:
                        self.grid[empty_space][x] = self.grid[y][x]
                        self.grid[y][x] = None
                        empty_space += 1

class Shape:
    def __init__(self, blocks, color):
